#!/bin/bash
IFS=. read -r i1 i2 i3 i4 <<< "$1"; m=$(( -1 << (32 - $2) )); n=$(( ((i1<<24) | (i2<<16) | (i3<<8) | i4) & m )); f=$(( n + 1 )); l=$(( (n | ~m) - 1 )); printf "%d.%d.%d.%d - %d.%d.%d.%d" "$(( (f >> 24) & 255 ))" "$(( (f >> 16) & 255 ))" "$(( (f >> 8) & 255 ))" "$(( f & 255 ))" "$(( (l >> 24) & 255 ))" "$(( (l >> 16) & 255 ))" "$(( (l >> 8) & 255 ))" "$(( l & 255 ))"
